// Extract customer data from GHL webhook
const body = $input.item.json.body;
const customData = body.customData || {};
return {
  json: {
    contact_id: body.contact_id,
    first_name: customData.first_name,
    asset_description: customData.asset_description,
    vehicle: customData.vehicle,
    services_interested: customData.services_interested,
    services_interested_check: customData.services_interested_check,
    desired_packages: customData.desired_packages,
    additional_info: customData.message_notes,
  }
};

// Format conversation history for GPT-5 (SMS ONLY)
const messagesData = $('Get Conversation History').item.json.messages || {};
const allMessages = messagesData.messages || [];
const customerData = $('Parse Customer Data').item.json;

// Filter to SMS messages only (exclude emails, calls, etc.)
const smsMessages = allMessages.filter(msg => 
  msg.messageType === 'TYPE_SMS' || msg.messageType === 'SMS'
);

// Reverse to chronological order 
const sortedMessages = [...smsMessages].reverse();

// Format as conversation history with line breaks between messages
const conversationHistory = sortedMessages.map(msg => {
  const role = msg.direction === 'inbound' ? customerData.first_name : '{{YOUR_AI_AGENT_NAME}}';
  let content = msg.body || '';

  // Handle attachments (prevents blank messages when customers send images)
  if (msg.attachments && msg.attachments.length > 0 && !content) {
    content = '[Customer sent an image]';
  }

  return `${role}: ${content}`;
}).join('\n\n');

// Helper function to provide fallback for empty/missing values
const notProvided = (value) => value || '(not provided)';

return {
  json: {
    conversation_history: conversationHistory,
    contact_id: customerData.contact_id,
    first_name: notProvided(customerData.first_name),
    asset_description: notProvided(customerData.asset_description),
    vehicle: notProvided(customerData.vehicle),
    services_interested: notProvided(customerData.services),
    services_interested_check: notProvided(customerData.services_interested_check),
    desired_packages: notProvided(customerData.desired_packages),
    additional_info: notProvided(customerData.additional_info),
  }
};

// Strip ##HANDOFF## marker from LLM response
const llmResponse = $input.item.json.text || '';

return {
  json: {
    ...$input.item.json,
    text: llmResponse.replace('##HANDOFF##', '').trim()
  }
};

// Get all messages 
const messages = $input.item.json.messages.messages || [];

if (!messages || messages.length === 0) {
  return { json: { shouldStop: false, reason: 'no_messages' } };
}

// Known human userIds from GHL team ({{YOUR_BUSINESS_NAME}})
const HUMAN_IDS = [
  'YOUR_EMPLOYEE_4_USER_ID', // {{YOUR_EMPLOYEE_NAME}}
  'YOUR_EMPLOYEE_1_USER_ID', // {{YOUR_EMPLOYEE_NAME}} ({{YOUR_DOMAIN}})
  'YOUR_EMPLOYEE_5_USER_ID', // {{YOUR_EMPLOYEE_NAME}} ({{YOUR_DOMAIN}})
  'YOUR_EMPLOYEE_6_USER_ID', // {{YOUR_EMPLOYEE_NAME}}
];

// Check if ANY call exists (inbound or outbound, regular or IVR)
// The AI agent never makes calls, so any call = human intervention
const hasHumanCall = messages.some(msg => 
  msg.messageType === 'TYPE_CALL' || msg.messageType === 'TYPE_IVR_CALL'
);

// Check if ANY human sent an SMS (must check userId since {{YOUR_AI_AGENT_NAME}} also sends SMS)
const hasHumanSMS = messages.some(msg => 
  msg.messageType === 'TYPE_SMS' && 
  msg.direction === 'outbound' &&
  msg.userId && 
  HUMAN_IDS.includes(msg.userId)
);

const shouldStop = hasHumanCall || hasHumanSMS;

let reason = 'none';
if (hasHumanCall) reason = 'human_call_detected';
if (hasHumanSMS) reason = 'human_sms_detected';
if (hasHumanCall && hasHumanSMS) reason = 'multiple_human_interventions';

return { 
  json: { 
    shouldStop,
    reason,
    hasHumanCall,
    hasHumanSMS
  } 
};

